// MARK: - Crypto Utilities
class CryptoWallet {
    private let privateKey: String
    public let publicKey: String
    public let address: String
    
    init() {
        let privateKeyData = CryptoWallet.generatePrivateKey()
        self.privateKey = privateKeyData.hexString
        let publicKeyData = CryptoWallet.derivePublicKey(from: privateKeyData)
        self.publicKey = publicKeyData.hexString
        self.address = CryptoWallet.deriveAddress(from: publicKeyData)
    }
    
    init(privateKey: String) throws {
        guard let privateKeyData = Data(hexString: privateKey), privateKeyData.count == 32 else {
            throw WalletError.invalidPrivateKey
        }
        self.privateKey = privateKey
        let publicKeyData = CryptoWallet.derivePublicKey(from: privateKeyData)
        self.publicKey = publicKeyData.hexString
        self.address = CryptoWallet.deriveAddress(from: publicKeyData)
    }
    
    static func generatePrivateKey() -> Data {
        var bytes = [UInt8](repeating: 0, count: 32)
        _ = SecRandomCopyBytes(kSecRandomDefault, bytes.count, &bytes)
        return Data(bytes)
    }
    
    static func derivePublicKey(from privateKey: Data) -> Data {
        let privateKeyHex = privateKey.hexString
        let curve = EllipticCurveSecp256k1()
        return curve.publicKey(from: privateKey)
    }
    
    static func deriveAddress(from publicKey: Data) -> String {
        let hash = publicKey.sha256().sha256()
        let addressData = hash.suffix(20)
        return "0x" + addressData.hexString
    }
    
    func getPrivateKey() -> String {
        return privateKey
    }
    
    func signTransaction(transaction: Transaction) throws -> String {
        let txData = transaction.serialize()
        let hash = txData.sha256()
        
        guard let privateKeyData = Data(hexString: privateKey) else {
            throw WalletError.invalidPrivateKey
        }
        
        let curve = EllipticCurveSecp256k1()
        let signature = curve.sign(message: hash, privateKey: privateKeyData)
        
        return signature.hexString
    }
}

// MARK: - Elliptic Curve Implementation
class EllipticCurveSecp256k1 {
    func publicKey(from privateKey: Data) -> Data {
        let context = secp256k1_context_create(UInt32(SECP256K1_CONTEXT_SIGN | SECP256K1_CONTEXT_VERIFY))!
        defer { secp256k1_context_destroy(context) }
        
        var publicKey = secp256k1_pubkey()
        var privateKeyBytes = [UInt8](privateKey)
        
        _ = secp256k1_ec_pubkey_create(context, &publicKey, &privateKeyBytes)
        
        var serializedPubKey = [UInt8](repeating: 0, count: 65)
        var outputLen = 65
        
        secp256k1_ec_pubkey_serialize(context, &serializedPubKey, &outputLen, &publicKey, UInt32(SECP256K1_EC_UNCOMPRESSED))
        
        return Data(serializedPubKey)
    }
    
    func sign(message: Data, privateKey: Data) -> Data {
        let context = secp256k1_context_create(UInt32(SECP256K1_CONTEXT_SIGN))!
        defer { secp256k1_context_destroy(context) }
        
        var signature = secp256k1_ecdsa_signature()
        var messageBytes = [UInt8](message)
        var privateKeyBytes = [UInt8](privateKey)
        
        _ = secp256k1_ecdsa_sign(context, &signature, &messageBytes, &privateKeyBytes, nil, nil)
        
        var compactSig = [UInt8](repeating: 0, count: 64)
        secp256k1_ecdsa_signature_serialize_compact(context, &compactSig, &signature)
        
        return Data(compactSig)
    }
}

// MARK: - Transaction Model
struct Transaction {
    let from: String
    let to: String
    let amount: Double
    let nonce: Int
    let gasPrice: Double
    let gasLimit: Int
    var signature: String?
    
    func serialize() -> Data {
        let dict: [String: Any] = [
            "from": from,
            "to": to,
            "amount": amount,
            "nonce": nonce,
            "gasPrice": gasPrice,
            "gasLimit": gasLimit
        ]
        
        let jsonString = dict.sorted(by: { $0.key < $1.key })
            .map { "\($0.key):\($0.value)" }
            .joined(separator: ",")
        
        return jsonString.data(using: .utf8) ?? Data()
    }
}

