// MARK: - Blockchain Communication
class BlockchainClient {
    private let baseURL: String
    
    init(nodeURL: String = "https://mainnet.infura.io/v3/YOUR_API_KEY") {
        self.baseURL = nodeURL
    }
    
    func getBalance(for address: String, completion: @escaping (Result<Double, Error>) -> Void) {
        let params: [String: Any] = [
            "jsonrpc": "2.0",
            "method": "eth_getBalance",
            "params": [address, "latest"],
            "id": 1
        ]
        
        makeRequest(params: params) { result in
            switch result {
            case .success(let response):
                if let balanceHex = response["result"] as? String {
                    let balance = Double(balanceHex.dropFirst(2), radix: 16) ?? 0
                    let etherBalance = balance / 1_000_000_000_000_000_000
                    completion(.success(etherBalance))
                } else {
                    completion(.failure(WalletError.invalidResponse))
                }
            case .failure(let error):
                completion(.failure(error))
            }
        }
    }
    
    func getNonce(for address: String, completion: @escaping (Result<Int, Error>) -> Void) {
        let params: [String: Any] = [
            "jsonrpc": "2.0",
            "method": "eth_getTransactionCount",
            "params": [address, "latest"],
            "id": 1
        ]
        
        makeRequest(params: params) { result in
            switch result {
            case .success(let response):
                if let nonceHex = response["result"] as? String {
                    let nonce = Int(nonceHex.dropFirst(2), radix: 16) ?? 0
                    completion(.success(nonce))
                } else {
                    completion(.failure(WalletError.invalidResponse))
                }
            case .failure(let error):
                completion(.failure(error))
            }
        }
    }
    
    func sendTransaction(_ transaction: Transaction, completion: @escaping (Result<String, Error>) -> Void) {
        guard let signature = transaction.signature else {
            completion(.failure(WalletError.transactionNotSigned))
            return
        }
        
        let rawTx = createRawTransaction(transaction: transaction, signature: signature)
        
        let params: [String: Any] = [
            "jsonrpc": "2.0",
            "method": "eth_sendRawTransaction",
            "params": [rawTx],
            "id": 1
        ]
        
        makeRequest(params: params) { result in
            switch result {
            case .success(let response):
                if let txHash = response["result"] as? String {
                    completion(.success(txHash))
                } else if let error = response["error"] as? [String: Any],
                          let message = error["message"] as? String {
                    completion(.failure(WalletError.networkError(message)))
                } else {
                    completion(.failure(WalletError.invalidResponse))
                }
            case .failure(let error):
                completion(.failure(error))
            }
        }
    }
    
    func getGasPrice(completion: @escaping (Result<Double, Error>) -> Void) {
        let params: [String: Any] = [
            "jsonrpc": "2.0",
            "method": "eth_gasPrice",
            "params": [],
            "id": 1
        ]
        
        makeRequest(params: params) { result in
            switch result {
            case .success(let response):
                if let gasPriceHex = response["result"] as? String {
                    let gasPrice = Double(gasPriceHex.dropFirst(2), radix: 16) ?? 0
                    let gwei = gasPrice / 1_000_000_000
                    completion(.success(gwei))
                } else {
                    completion(.failure(WalletError.invalidResponse))
                }
            case .failure(let error):
                completion(.failure(error))
            }
        }
    }
    
    private func makeRequest(params: [String: Any], completion: @escaping (Result<[String: Any], Error>) -> Void) {
        guard let url = URL(string: baseURL) else {
            completion(.failure(WalletError.invalidURL))
            return
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        
        do {
            request.httpBody = try JSONSerialization.data(withJSONObject: params)
        } catch {
            completion(.failure(error))
            return
        }
        
        URLSession.shared.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(.failure(error))
                return
            }
            
            guard let data = data else {
                completion(.failure(WalletError.noData))
                return
            }
            
            do {
                if let json = try JSONSerialization.jsonObject(with: data) as? [String: Any] {
                    completion(.success(json))
                } else {
                    completion(.failure(WalletError.invalidResponse))
                }
            } catch {
                completion(.failure(error))
            }
        }.resume()
    }
    
    private func createRawTransaction(transaction: Transaction, signature: String) -> String {
        return "0x" + signature
    }
}

// MARK: - Wallet Manager
class WalletManager {
    static let shared = WalletManager()
    private let secureStorage = SecureStorage()
    private var wallets: [CryptoWallet] = []
    
    private init() {
        loadWallets()
    }
    
    func createWallet() throws -> CryptoWallet {
        let wallet = CryptoWallet()
        try secureStorage.savePrivateKey(wallet.getPrivateKey(), for: wallet.address)
        wallets.append(wallet)
        saveWalletAddresses()
        return wallet
    }
    
    func importWallet(privateKey: String) throws -> CryptoWallet {
        let wallet = try CryptoWallet(privateKey: privateKey)
        try secureStorage.savePrivateKey(wallet.getPrivateKey(), for: wallet.address)
        wallets.append(wallet)
        saveWalletAddresses()
        return wallet
    }
    
    func getWallets() -> [CryptoWallet] {
        return wallets
    }
    
    func deleteWallet(address: String) throws {
        try secureStorage.deletePrivateKey(for: address)
        wallets.removeAll { $0.address == address }
        saveWalletAddresses()
    }
    
    private func loadWallets() {
        let addresses = secureStorage.loadWalletAddresses()
        wallets = addresses.compactMap { address in
            guard let privateKey = try? secureStorage.loadPrivateKey(for: address),
                  let wallet = try? CryptoWallet(privateKey: privateKey) else {
                return nil
            }
            return wallet
        }
    }
    
    private func saveWalletAddresses() {
        let addresses = wallets.map { $0.address }
        try? secureStorage.saveWalletAddresses(addresses)
    }
}

// MARK: - Errors
enum WalletError: LocalizedError {
    case invalidPrivateKey
    case privateKeyNotFound
    case keychainError
    case invalidResponse
    case noData
    case invalidURL
    case transactionNotSigned
    case networkError(String)
    
    var errorDescription: String? {
        switch self {
        case .invalidPrivateKey:
            return "Invalid private key format"
        case .privateKeyNotFound:
            return "Private key not found in secure storage"
        case .keychainError:
            return "Keychain access error"
        case .invalidResponse:
            return "Invalid response from blockchain"
        case .noData:
            return "No data received"
        case .invalidURL:
            return "Invalid blockchain URL"
        case .transactionNotSigned:
            return "Transaction must be signed before sending"
        case .networkError(let message):
            return "Network error: \(message)"
        }
    }
}

// MARK: - Extensions
extension Data {
    var hexString: String {
        return map { String(format: "%02x", $0) }.joined()
    }
    
    init?(hexString: String) {
        let len = hexString.count / 2
        var data = Data(capacity: len)
        var index = hexString.startIndex
        for _ in 0..<len {
            let nextIndex = hexString.index(index, offsetBy: 2)
            if let byte = UInt8(hexString[index..<nextIndex], radix: 16) {
                data.append(byte)
            } else {
                return nil
            }
            index = nextIndex
        }
        self = data
    }
    
    func sha256() -> Data {
        var hash = [UInt8](repeating: 0, count: Int(CC_SHA256_DIGEST_LENGTH))
        self.withUnsafeBytes {
            _ = CC_SHA256($0.baseAddress, CC_LONG(self.count), &hash)
        }
        return Data(hash)
    }
}

// MARK: - View Controllers
class WalletListViewController: UIViewController {
    private let tableView = UITableView()
    private var wallets: [CryptoWallet] = []
    private var balances: [String: Double] = [:]
    private let blockchainClient = BlockchainClient()
    
    override func viewDidLoad() {
        super.viewDidLoad()
        setupUI()
        loadWallets()
    }
    
    private func setupUI() {
        title = "My Wallets"
        view.backgroundColor = .systemBackground
        
        navigationItem.rightBarButtonItem = UIBarButtonItem(barButtonSystemItem: .add, target: self, action: #selector(addWallet))
        
        tableView.delegate = self
        tableView.dataSource = self
        tableView.register(WalletCell.self, forCellReuseIdentifier: "WalletCell")
        tableView.frame = view.bounds
        tableView.autoresizingMask = [.flexibleWidth, .flexibleHeight]
        view.addSubview(tableView)
    }
    
    private func loadWallets() {
        wallets = WalletManager.shared.getWallets()
        tableView.reloadData()
        loadBalances()
    }
    
    private func loadBalances() {
        for wallet in wallets {
            blockchainClient.getBalance(for: wallet.address) { [weak self] result in
                DispatchQueue.main.async {
                    if case .success(let balance) = result {
                        self?.balances[wallet.address] = balance
                        self?.tableView.reloadData()
                    }
                }
            }
        }
    }
    
    @objc private func addWallet() {
        let alert = UIAlertController(title: "Add Wallet", message: nil, preferredStyle: .actionSheet)
        
        alert.addAction(UIAlertAction(title: "Create New Wallet", style: .default) { [weak self] _ in
            self?.createNewWallet()
        })
        
        alert.addAction(UIAlertAction(title: "Import Wallet", style: .default) { [weak self] _ in
            self?.importWallet()
        })
        
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel))
        
        present(alert, animated: true)
    }
    
    private func createNewWallet() {
        do {
            let wallet = try WalletManager.shared.createWallet()
            wallets.append(wallet)
            tableView.reloadData()
            
            let alert = UIAlertController(title: "Wallet Created", message: "Address: \(wallet.address)\n\nPlease backup your private key securely!", preferredStyle: .alert)
            alert.addAction(UIAlertAction(title: "View Private Key", style: .default) { _ in
                self.showPrivateKey(wallet)
            })
            alert.addAction(UIAlertAction(title: "OK", style: .default))
            present(alert, animated: true)
        } catch {
            showError(error)
        }
    }
    
    private func importWallet() {
        let alert = UIAlertController(title: "Import Wallet", message: "Enter your private key", preferredStyle: .alert)
        alert.addTextField { textField in
            textField.placeholder = "Private Key (hex)"
            textField.autocapitalizationType = .none
            textField.autocorrectionType = .no
        }
        
        alert.addAction(UIAlertAction(title: "Import", style: .default) { [weak self] _ in
            guard let privateKey = alert.textFields?.first?.text else { return }
            do {
                let wallet = try WalletManager.shared.importWallet(privateKey: privateKey)
                self?.wallets.append(wallet)
                self?.tableView.reloadData()
            } catch {
                self?.showError(error)
            }
        })
        
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel))
        present(alert, animated: true)
    }
    
    private func showPrivateKey(_ wallet: CryptoWallet) {
        let alert = UIAlertController(title: "Private Key", message: wallet.getPrivateKey(), preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "Copy", style: .default) { _ in
            UIPasteboard.general.string = wallet.getPrivateKey()
        })
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        present(alert, animated: true)
    }
    
    private func showError(_ error: Error) {
        let alert = UIAlertController(title: "Error", message: error.localizedDescription, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        present(alert, animated: true)
    }
}

extension WalletListViewController: UITableViewDelegate, UITableViewDataSource {
    func tableView(_ tableView: UITableView, numberOfRowsInSection section: Int) -> Int {
        return wallets.count
    }
    
    func tableView(_ tableView: UITableView, cellForRowAt indexPath: IndexPath) -> UITableViewCell {
        let cell = tableView.dequeueReusableCell(withIdentifier: "WalletCell", for: indexPath) as! WalletCell
        let wallet = wallets[indexPath.row]
        let balance = balances[wallet.address] ?? 0
        cell.configure(address: wallet.address, balance: balance)
        return cell
    }
    
    func tableView(_ tableView: UITableView, didSelectRowAt indexPath: IndexPath) {
        tableView.deselectRow(at: indexPath, animated: true)
        let wallet = wallets[indexPath.row]
        let detailVC = WalletDetailViewController(wallet: wallet)
        navigationController?.pushViewController(detailVC, animated: true)
    }
    
    func tableView(_ tableView: UITableView, commit editingStyle: UITableViewCell.EditingStyle, forRowAt indexPath: IndexPath) {
        if editingStyle == .delete {
            let wallet = wallets[indexPath.row]
            do {
                try WalletManager.shared.deleteWallet(address: wallet.address)
                wallets.remove(at: indexPath.row)
                tableView.deleteRows(at: [indexPath], with: .fade)
            } catch {
                showError(error)
            }
        }
    }
}

