    }
    
    @objc private func sendTransaction() {
        let alert = UIAlertController(title: "Send Transaction", message: nil, preferredStyle: .alert)
        alert.addTextField { $0.placeholder = "Recipient Address" }
        alert.addTextField { $0.placeholder = "Amount (ETH)"; $0.keyboardType = .decimalPad }
        
        alert.addAction(UIAlertAction(title: "Send", style: .default) { [weak self] _ in
            guard let self = self,
                  let to = alert.textFields?[0].text,
                  let amountStr = alert.textFields?[1].text,
                  let amount = Double(amountStr) else { return }
            
            self.performTransaction(to: to, amount: amount)
        })
        
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel))
        present(alert, animated: true)
    }
    
    private func performTransaction(to: String, amount: Double) {
        blockchainClient.getNonce(for: wallet.address) { [weak self] result in
            guard let self = self else { return }
            
            switch result {
            case .success(let nonce):
                self.blockchainClient.getGasPrice { gasPriceResult in
                    switch gasPriceResult {
                    case .success(let gasPrice):
                        var transaction = Transaction(
                            from: self.wallet.address,
                            to: to,
                            amount: amount,
                            nonce: nonce,
                            gasPrice: gasPrice,
                            gasLimit: 21000
                        )
                        
                        do {
                            let signature = try self.wallet.signTransaction(transaction: transaction)
                            transaction.signature = signature
                            
                            self.blockchainClient.sendTransaction(transaction) { sendResult in
                                DispatchQueue.main.async {
                                    switch sendResult {
                                    case .success(let txHash):
                                        let alert = UIAlertController(title: "Success", message: "Transaction sent!\nHash: \(txHash)", preferredStyle: .alert)
                                        alert.addAction(UIAlertAction(title: "OK", style: .default))
                                        self.present(alert, animated: true)
                                        self.loadBalance()
                                    case .failure(let error):
                                        self.showError(error)
                                    }
                                }
                            }
                        } catch {
                            DispatchQueue.main.async {
                                self.showError(error)
                            }
                        }
                    case .failure(let error):
                        DispatchQueue.main.async {
                            self.showError(error)
                        }
                    }
                }
            case .failure(let error):
                DispatchQueue.main.async {
                    self.showError(error)
                }
            }
        }
    }
    
    @objc private func showReceiveAddress() {
        let alert = UIAlertController(title: "Receive", message: "Your Address:\n\n\(wallet.address)", preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "Copy", style: .default) { _ in
            UIPasteboard.general.string = self.wallet.address
        })
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        present(alert, animated: true)
    }
    
    @objc private func exportPrivateKey() {
        let alert = UIAlertController(title: "Warning", message: "Never share your private key with anyone!", preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "Show Private Key", style: .destructive) { _ in
            self.showPrivateKey()
        })
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel))
        present(alert, animated: true)
    }
    
    private func showPrivateKey() {
        let alert = UIAlertController(title: "Private Key", message: wallet.getPrivateKey(), preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "Copy", style: .default) { _ in
            UIPasteboard.general.string = self.wallet.getPrivateKey()
        })
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        present(alert, animated: true)
    }
    
    private func showError(_ error: Error) {
        let alert = UIAlertController(title: "Error", message: error.localizedDescription, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        present(alert, animated: true)
    }
}

@main
class AppDelegate: UIResponder, UIApplicationDelegate {
    var window: UIWindow?
    
    func application(_ application: UIApplication, didFinishLaunchingWithOptions launchOptions: [UIApplication.LaunchOptionsKey: Any]?) -> Bool {
        window = UIWindow(frame: UIScreen.main.bounds)
        let walletListVC = WalletListViewController()
        let navController = UINavigationController(rootViewController: walletListVC)
        window?.rootViewController = navController
        window?.makeKeyAndVisible()
        return true
    }
}